// Lista de processos ativos — CNJ SEM FORMATAÇÃO (DataJud exige)
// Atualizar conforme novas nomeações
const processos = [
  { cnj: "01029355820038130396", cnj_fmt: "0102935-58.2003.8.13.0396", alias: "Processo Antigo 396", tribunal: "api_publica_tjmg" },
  { cnj: "50006284620198130309", cnj_fmt: "5000628-46.2019.8.13.0309", alias: "Perícia 22 Inhapim", tribunal: "api_publica_tjmg" },
  { cnj: "50016159820258130074", cnj_fmt: "5001615-98.2025.8.13.0074", alias: "Perícia 14 Bom Despacho", tribunal: "api_publica_tjmg" },
  { cnj: "50024246220258130309", cnj_fmt: "5002424-62.2025.8.13.0309", alias: "Contestação Inhapim", tribunal: "api_publica_tjmg" },
  { cnj: "50025266020248130005", cnj_fmt: "5002526-60.2024.8.13.0005", alias: "Pendente Laudo", tribunal: "api_publica_tjmg" },
  { cnj: "50031337920218130231", cnj_fmt: "5003133-79.2021.8.13.0231", alias: "Pendente Agendamento", tribunal: "api_publica_tjmg" },
  { cnj: "50044628120248130309", cnj_fmt: "5004462-81.2024.8.13.0309", alias: "Perícia 7 Inhapim", tribunal: "api_publica_tjmg" },
  { cnj: "50052673020258130105", cnj_fmt: "5005267-30.2025.8.13.0105", alias: "Pendente Aceite 105", tribunal: "api_publica_tjmg" },
  { cnj: "50074094820208130245", cnj_fmt: "5007409-48.2020.8.13.0245", alias: "Pendente Aceite 245", tribunal: "api_publica_tjmg" },
  { cnj: "50082977320258130105", cnj_fmt: "5008297-73.2025.8.13.0105", alias: "Pendente Aceite 105-2", tribunal: "api_publica_tjmg" },
  { cnj: "50140175520248130105", cnj_fmt: "5014017-55.2024.8.13.0105", alias: "Pendente Aceite 105-3", tribunal: "api_publica_tjmg" },
  { cnj: "50163667020208130105", cnj_fmt: "5016366-70.2020.8.13.0105", alias: "Pendente Aceite 105-4", tribunal: "api_publica_tjmg" },
  { cnj: "50177004220208130105", cnj_fmt: "5017700-42.2020.8.13.0105", alias: "Pendente Agendamento 105", tribunal: "api_publica_tjmg" },
  { cnj: "50658154420238130702", cnj_fmt: "5065815-44.2023.8.13.0702", alias: "Pendente Agendamento 702", tribunal: "api_publica_tjmg" }
];

// Data de corte: últimas 72h (3 dias — margem de segurança)
const agora = new Date();
const corte = new Date(agora.getTime() - 72 * 60 * 60 * 1000);
const dataCorte = corte.toISOString().split('T')[0];

return processos.map(p => ({
  json: { ...p, data_corte: dataCorte }
}));

const items = $input.all();
const novidades = [];

for (const item of items) {
  const data = item.json;
  const alias = data.alias || data.cnj;

  // Se a API retornou hits
  const hits = data?.hits?.hits || data?.body?.hits?.hits || [];

  if (hits.length === 0) continue;

  const processo = hits[0]._source || hits[0];
  const movimentos = processo.movimentos || [];
  const dataCorte = new Date(data.data_corte || '2026-01-01');

  // Filtrar movimentos recentes
  const recentes = movimentos.filter(m => {
    const dataM = new Date(m.dataHora);
    return dataM >= dataCorte;
  });

  if (recentes.length === 0) continue;

  // Classificar tipo de movimentação
  for (const mov of recentes) {
    const nome = (mov.nome || '').toLowerCase();
    const complementos = (mov.complementosTabelados || []).map(c => (c.nome || '').toLowerCase()).join(' ');
    const textoCompleto = nome + ' ' + complementos;

    let tipo = 'MOVIMENTAÇÃO';
    let urgente = false;

    if (textoCompleto.includes('nomeação') || textoCompleto.includes('perito')) {
      tipo = '🔵 NOMEAÇÃO';
      urgente = true;
    } else if (textoCompleto.includes('intimação') || textoCompleto.includes('intimado')) {
      tipo = '🔴 INTIMAÇÃO';
      urgente = true;
    } else if (textoCompleto.includes('prazo')) {
      tipo = '⏰ PRAZO';
      urgente = true;
    } else if (textoCompleto.includes('despacho')) {
      tipo = '📋 DESPACHO';
    } else if (textoCompleto.includes('decisão')) {
      tipo = '⚖️ DECISÃO';
      urgente = true;
    } else if (textoCompleto.includes('juntada') || textoCompleto.includes('petição')) {
      tipo = '📎 JUNTADA';
    } else if (textoCompleto.includes('sentença')) {
      tipo = '🏛️ SENTENÇA';
      urgente = true;
    }

    novidades.push({
      cnj: data.cnj_fmt || data.cnj,
      alias: alias,
      tipo: tipo,
      movimento: mov.nome || 'Sem nome',
      data: mov.dataHora ? new Date(mov.dataHora).toLocaleDateString('pt-BR') : '?',
      complementos: complementos,
      urgente: urgente,
      orgao: processo.orgaoJulgador?.nome || ''
    });
  }
}

if (novidades.length === 0) {
  return [{ json: { tem_novidade: false, mensagem: 'Nenhuma novidade nos últimos 2 dias.' } }];
}

// Montar mensagem do Telegram
const urgentes = novidades.filter(n => n.urgente);
const normais = novidades.filter(n => !n.urgente);

let msg = '📋 MONITOR STEMMIA — ' + new Date().toLocaleDateString('pt-BR') + '\n\n';

if (urgentes.length > 0) {
  msg += '🚨 URGENTES:\n';
  for (const n of urgentes) {
    msg += `${n.tipo} | ${n.alias}\n`;
    msg += `   ${n.movimento} (${n.data})\n`;
    if (n.orgao) msg += `   ${n.orgao}\n`;
    msg += '\n';
  }
}

if (normais.length > 0) {
  msg += '📌 Outras movimentações:\n';
  for (const n of normais) {
    msg += `${n.tipo} | ${n.alias} — ${n.movimento} (${n.data})\n`;
  }
}

msg += '\n✅ ' + novidades.length + ' movimentação(ões) detectada(s)';

return [{ json: { tem_novidade: true, mensagem: msg, novidades: novidades, total: novidades.length } }];
